   278→func (s *EtcdServer) waitAppliedIndex() error {
   279→	select {
   280→	case <-s.ApplyWait():
   281→	case <-s.stopping:
   282→		return ErrStopped
   283→	case <-time.After(applyTimeout):
   284→		return ErrTimeoutWaitAppliedIndex
   285→	}
   286→
   287→	return nil
   288→}
