   146→	if len(revpairs) == 0 {
   147→		return &RangeResult{KVs: nil, Count: total, Rev: curRev}, nil
   148→	}
   149→
   150→	limit := int(ro.Limit)
   151→	if limit <= 0 || limit > len(revpairs) {
   152→		limit = len(revpairs)
   153→	}
   154→
   155→	kvs := make([]mvccpb.KeyValue, limit)
