 }\nfunc (tr *storeTxnRead) Rev() int64      { return tr.rev }\n\nfunc (tr *storeTxnRead) Range(ctx context.Context, key, end []byte, ro RangeOptions) (r *RangeResult, err error) {\n\treturn tr.rangeKeys(ctx, key, end, tr.Rev(), ro)\n}\n\nfunc (tr *storeTxnRead) End() {\n\ttr.tx.RUnlock() // RUnlock signals the end of concurrentReadTx.\n\ttr.s.mu.RUnlock()\n}\n\ntype storeTxnWrite struct {\n\tstoreTxnRead\n\ttx backend.BatchTx\n\t// beginRev is the revision where the txn begins; it will write to the next revision.\n\tbeginRev int64\n\tchanges  []mvccpb.KeyValue\n}\n\nfunc (s *store) Write(trace *traceutil.Trace) TxnWrite {\n\ts.mu.RLock()\n\ttx := s.b.BatchTx()\n\ttx.LockInsideApply()\n\ttw := &storeTxnWrite{\n\t\tstoreTxnRead: storeTxnRead{s, tx, 0, 0, trace},\n\t\ttx:           tx,\n\t\tbeginRev:     s.currentRev,\n\t\tchanges:      make([]mvccpb.KeyValue, 0, 4),\n\t}\n\treturn newMetricsTxnWrite(tw)\n}\n\nfunc (tw *storeTxnWrite) Rev() int64 { return tw.beginRev }\n\nfunc (tw *storeTxnWrite) Range(ctx context.Context, key, end []byte, ro RangeOptions) (r *RangeResult, err error) {\n\trev := tw.beginRev\n\tif len(tw.changes) > 0 {\n\t\trev++\n\t}\n\treturn tw.rangeKeys(ctx, key, end, rev, ro)\n}\n\nfunc (tw *storeTxnWrite) DeleteRange(key, end []byte) (int64, int64) {\n\tif n := tw.deleteRange(key, end); n != 0 || len(tw.changes) > 0 {\n\t\treturn n, tw.beginRev + 1\n\t}\n\treturn 0, tw.beginRev\n}\n\nfunc (tw *storeTxnWrite) Put(key, value []byte, lease lease.LeaseID) int64 {\n\ttw.put(key, value, lease)\n\treturn tw.beginRev + 1\n}\n\nfunc (tw *storeTxnWrite) End() {\n\t// only update index if the txn modifies the mvcc state.\n\tif len(tw.changes) != 0 {\n\t\t// hold revMu lock to prevent new read txns from opening until writeback.\n\t\ttw.s.revMu.Lock()\n\t\ttw.s.currentRev++\n\t}\n\ttw.tx.Unlock()\n\tif len(tw.changes) != 0 {\n\t\ttw.s.revMu.Unlock()\n\t}\n\ttw.s.mu.RUnlock()\n}\n\nfunc (tr *storeTxnRead) rangeKeys(ctx context.Context, key, end []byte, curRev int64, ro RangeOptions) (*RangeResult, error) {\n\trev := ro.Rev\n\tif rev > curRev {\n\t\treturn &RangeResult{KVs: nil, Count: -1, Rev: curRev}, ErrFutureRev\n\t}\n\tif rev <= 0 {\n\t\trev = curRev\n\t}\n\tif rev < tr.s.compactMainRev {\n\t\treturn &RangeResult{KVs: nil, Count: -1, Rev: 0}, ErrCompacted\n\t}\n\tif ro.Count {\n\t\ttotal := tr.s.kvindex.CountRevisions(key, end, rev)\n\t\ttr.trace.Step(\"count revisions from in-memory index tree\")\n\t\treturn &RangeResult{KVs: nil, Count: total, Rev: curRev}, nil\n\t}\n\trevpairs, total := tr.s.kvindex.Revisions(key, end, rev, int(ro.Limit))\n\ttr.trace.Step(\"range keys from in-memory index tree\")\n\tif len(revpairs) == 0 {\n\t\treturn &RangeResult{KVs: nil, Count: total, Rev: curRev}, nil\n\t}\n\n\tlimit := int(ro.Limit)\n\tif limit <= 0 || limit > len(revpairs) {\n\t\tlimit = len(revpairs)\n\t}\n\n\tkvs := make([]mvccpb.KeyValue, limit)\n\trevBytes := newRevBytes()\n\tfor i, revpair := range revpairs[:len(kvs)] {\n\t\tselect {\n\t\tcase <-ctx.Done():\n\t\t\treturn nil, fmt.Errorf(\"rangeKeys: context cancelled: %w\", ctx.Err())\n\t\tdefault:\n\t\t}\n\t\trevToBytes(revpair, revBytes)\n\t\t_, vs := tr.tx.UnsafeRange(buckets.Key, revBytes, nil, 0)\n\t\tif len(vs) != 1 {\n\t\t\ttr.s.lg.Fatal(\n\t\t\t\t\"range failed to find revision pair\",\n\t\t\t\tzap.Int64(\"revision-main\", revpair.main),\n\t\t\t\tzap.Int64(\"revision-sub\", revpair.sub),\n\t\t\t\tzap.Int64(\"revision-current\", curRev),\n\t\t\t\tzap.Int64(\"range-option-rev\", ro.Rev),\n\t\t\t\tzap.Int64(\"range-option-limit\", ro.Limit),\n\t\t\t\tzap.Binary(\"key\", key),\n\t\t\t\tzap.Binary(\"end\", end),\n\t\t\t\tzap.Int(\"len-revpairs\", len(revpairs)),\n\t\t\t\tzap.Int(\"len-values\", len(vs)),\n\t\t\t)\n\t\t}\n\t\tif err := kvs[i].Unmarshal(vs[0]); err != nil {\n\t\t\ttr.s.lg.Fatal(\n\t\t\t\t\"failed to unmarshal mvccpb.KeyValue\",\n\t\t\t\tzap.Error(err),\n\t\t\t)\n\t\t}\n\t}\n\ttr.trace.Step(\"range keys from bolt db\")\n\treturn &RangeResult{KVs: kvs, Count: total, Rev: curRev}, nil\n}\n\nfunc (tw *storeTxnWrite) put(key, value []byte, leaseID lease.LeaseID) {\n\trev := tw.beginRev + 1\n\tc := rev\n\toldLease := lease.NoLease\n\n\t// if the key exists before, use its previous created and\n\t// get its previous leaseID\n\t_, created, ver, err := tw.s.kvindex.Get(key, rev)\n\tif err == nil {\n\t\tc = created.main\n\t\toldLease = tw.s.le.GetLease(lease.LeaseItem{Key: string(key)})\n\t\ttw.trace.Step(\"get key's previous created_revision and leaseID\")\n\t}\n\tibytes := newRevBytes()\n\tidxRev := revision{main: rev, sub: int64(len(tw.changes))}\n\trevToBytes(idxRev, ibytes)\n\n\tver = ver + 1\n\tkv := mvccpb.KeyValue{\n\t\tKey:            key,\n\t\tValue:          value,\n\t\tCreateRevision: c,\n\t\tModRevision:    rev,\n\t\tVersion:        ver,\n\t\tLease:          int64(leaseID),\n\t}\n\n\td, err := kv.Marshal()\n\tif err != nil {\n\t\ttw.storeTxnRead.s.lg.Fatal(\n\t\t\t\"failed to marshal mvccpb.KeyValue\",\n\t\t\tzap.Error(err),\n\t\t)\n\t}\n\n\ttw.trace.Step(\"marshal mvccpb.KeyValue\")\n\ttw.tx.UnsafeSeqPut(buckets.Key, ibytes, d)\n\ttw.s.kvindex.Put(key, idxRev)\n\ttw.changes = append(tw.changes, kv)\n\ttw.trace.Step(\"store kv pair into bolt db\")\n\n\tif oldLease != lease.NoLease {\n\t\tif tw.s.le == nil {\n\t\t\tpanic(\"no lessor to detach lease\")\n\t\t}\n\t\terr = tw.s.le.Detach(oldLease, []lease.LeaseItem{{Key: string(key)}})\n\t\tif err != nil {\n\t\t\ttw.storeTxnRead.s.lg.Error(\n\t\t\t\t\"failed to detach old lease from a key\",\n\t\t\t\tzap.Error(err),\n\t\t\t)\n\t\t}\n\t}\n\tif leaseID != lease.NoLease {\n\t\tif tw.s.le == nil {\n\t\t\tpanic(\"no lessor to attach lease\")\n\t\t}\n\t\terr = tw.s.le.Attach(leaseID, []lease.LeaseItem{{Key: string(key)}})\n\t\tif err != nil {\n\t\t\tpanic(\"unexpected error from lease Attach\")\n\t\t}\n\t}\n\ttw.trace.Step(\"attach lease to kv pair\")\n}\n\nfunc (tw *storeTxnWrite) deleteRange(key, end []byte) int64 {\n\trrev := tw.beginRev\n\tif len(tw.changes) > 0 {\n\t\trrev++\n\t}\n\tkeys, _ := tw.s.kvindex.Range(key, end, rrev)\n\tif len(keys) == 0 {\n\t\treturn 0\n\t}\n\tfor _, key := range keys {\n\t\ttw.delete(key)\n\t}\n\treturn int64(len(keys))\n}\n\nfunc (tw *storeTxnWrite) delete(key []byte) {\n\tibytes := newRevBytes()\n\tidxRev := revision{main: tw.beginRev + 1, sub: int64(len(tw.changes))}\n\trevToBytes(idxRev, ibytes)\n\n\tibytes = appendMarkTombstone(tw.storeTxnRead.s.lg, ibytes)\n\n\tkv := mvccpb.KeyValue{Key: key}\n\n\td, err := kv.Marshal()\n\tif err != nil {\n\t\ttw.storeTxnRead.s.lg.Fatal(\n\t\t\t\"failed to marshal mvccpb.KeyValue\",\n\t\t\tzap.Error(err),\n\t\t)\n\t}\n\n\ttw.tx.UnsafeSeqPut(buckets.Key, ibytes, d)\n\terr = tw.s.kvindex.Tombstone(key, idxRev)\n\tif err != nil {\n\t\ttw.storeTxnRead.s.lg.Fatal(\n\t\t\t\"failed to tombstone an existing key\",\n\t\t\tzap.String(\"key\", string(key)),\n\t\t\tzap.Error(err),\n\t\t)\n\t}\n\ttw.changes = append(tw.changes, kv)\n\n\titem := lease.LeaseItem{Key: string(key)}\n\tleaseID := tw.s.le.GetLease(item)\n\n\tif leaseID != lease.NoLease {\n\t\terr = tw.s.le.Detach(leaseID, []lease.LeaseItem{item})\n\t\tif err != nil {\n\t\t\ttw.storeTxnRead.s.lg.Error(\n\t\t\t\t\"failed to detach old lease from a key\",\n\t\t\t\tzap.Error(err),\n\t\t\t)\n\t\t}\n\t}\n}\n\nfunc (tw *storeTxnWrite) Changes() []mvccpb.KeyValue { return tw.changes }\n", "numLines": 313, "startLine": 1, "totalLines": 313}}

